import { useState, useRef, useMemo } from "react";
import { useVirtualizer } from "@tanstack/react-virtual";

interface LedgerEntry {
  id: number;
  date: string;
  counterAccount: string;
  summary: string;
  debit: number | null;
  credit: number | null;
}

const ACCOUNTS = ["現金", "消耗品費", "買掛金", "給与手当", "通信費", "地代家賃", "売掛金", "水道光熱費", "売上高", "法定福利費", "租税公課", "受取利息", "支払手数料"];

// Generate 10,000 rows
const MOCK_ENTRIES: LedgerEntry[] = Array.from({ length: 10000 }).map((_, i) => {
  if (i === 0) return { id: 0, date: "", counterAccount: "", summary: "前月繰越", debit: null, credit: null };
  const isDebit = Math.random() > 0.5;
  const amount = Math.floor(Math.random() * 500000) + 1000;
  const month = String(Math.floor(Math.random() * 12) + 1).padStart(2, "0");
  const day = String(Math.floor(Math.random() * 28) + 1).padStart(2, "0");

  return {
    id: i,
    date: `${month}/${day}`,
    counterAccount: ACCOUNTS[Math.floor(Math.random() * ACCOUNTS.length)],
    summary: `ダミー取引データ ${i}`,
    debit: isDebit ? amount : null,
    credit: isDebit ? null : amount,
  };
});

const OPENING_BALANCE = 5_800_000;

function fmt(n: number | null): string {
  if (n === null || n === 0) return "";
  return n.toLocaleString();
}

export function SubsidiaryLedger() {
  const [selectedRow, setSelectedRow] = useState<number | null>(null);
  const [selectedAccount, setSelectedAccount] = useState("普通預金");
  const [selectedSub, setSelectedSub] = useState("みずほ銀行");

  // Compute running balances
  const entriesWithBalance = useMemo(() => {
    let balance = OPENING_BALANCE;
    return MOCK_ENTRIES.map((entry, idx) => {
      if (idx === 0) {
        return { ...entry, balance: OPENING_BALANCE };
      }
      balance += (entry.debit || 0) - (entry.credit || 0);
      return { ...entry, balance };
    });
  }, []);

  const parentRef = useRef<HTMLDivElement>(null);

  const rowVirtualizer = useVirtualizer({
    count: entriesWithBalance.length,
    getScrollElement: () => parentRef.current,
    estimateSize: () => 24, // High density, 24px per row
    overscan: 20,
  });

  return (
    <div
      className="flex flex-col h-full"
      style={{ fontFamily: "'Noto Sans JP', sans-serif" }}
    >
      {/* Title bar */}
      <div
        className="flex items-center justify-between px-2"
        style={{
          height: 26,
          backgroundColor: "#005BAC",
          color: "#fff",
          fontSize: 12,
        }}
      >
        <span>補助元帳</span>
        <span style={{ fontSize: 11 }}>令和7年4月 ｜ 令和7年度</span>
      </div>

      {/* Account selector */}
      <div
        className="flex items-center gap-3 px-2"
        style={{
          height: 30,
          backgroundColor: "#f5f5f5",
          borderBottom: "1px solid #c0c0c0",
          fontSize: 12,
        }}
      >
        <span style={{ color: "#555" }}>勘定科目:</span>
        <select
          value={selectedAccount}
          onChange={(e) => setSelectedAccount(e.target.value)}
          style={{
            fontSize: 12,
            padding: "1px 4px",
            border: "1px solid #b0b0b0",
            backgroundColor: "#fff",
            borderRadius: 2,
          }}
        >
          <option>普通預金</option>
          <option>現金</option>
          <option>売掛金</option>
          <option>買掛金</option>
        </select>
        <span style={{ color: "#555" }}>補助科目:</span>
        <select
          value={selectedSub}
          onChange={(e) => setSelectedSub(e.target.value)}
          style={{
            fontSize: 12,
            padding: "1px 4px",
            border: "1px solid #b0b0b0",
            backgroundColor: "#fff",
            borderRadius: 2,
          }}
        >
          <option>みずほ銀行</option>
          <option>三井住友銀行</option>
          <option>三菱UFJ銀行</option>
        </select>
        <div style={{ marginLeft: "auto", color: "#555" }}>
          期間:
          <input
            type="text"
            defaultValue="04/01"
            style={{
              width: 52,
              fontSize: 12,
              padding: "1px 4px",
              border: "1px solid #b0b0b0",
              textAlign: "center",
              marginLeft: 4,
              borderRadius: 2,
            }}
          />
          ～
          <input
            type="text"
            defaultValue="04/30"
            style={{
              width: 52,
              fontSize: 12,
              padding: "1px 4px",
              border: "1px solid #b0b0b0",
              textAlign: "center",
              borderRadius: 2,
            }}
          />
        </div>
      </div>

      {/* Header */}
      <div
        className="flex"
        style={{ backgroundColor: "#d0dce8", borderBottom: "2px solid #005BAC" }}
      >
        {[
          { label: "日付", width: 60 },
          { label: "相手勘定科目", width: 120 },
          { label: "摘要", width: "100%" },
          { label: "借方金額", width: 110 },
          { label: "貸方金額", width: 110 },
          { label: "残高", width: 120 },
        ].map((col) => (
          <div
            key={col.label}
            style={{
              width: col.width,
              padding: "4px 6px",
              borderRight: "1px solid #b0b0b0",
              textAlign: "center",
              fontSize: 11,
              color: "#333",
              flexShrink: col.width === "100%" ? 1 : 0,
              flexGrow: col.width === "100%" ? 1 : 0,
            }}
          >
            {col.label}
          </div>
        ))}
      </div>

      {/* Grid */}
      <div
        ref={parentRef}
        className="flex-1 overflow-auto bg-white"
        style={{ outline: "none" }}
        tabIndex={0}
      >
        <div
          style={{
            height: `${rowVirtualizer.getTotalSize()}px`,
            width: "100%",
            position: "relative",
          }}
        >
          {rowVirtualizer.getVirtualItems().map((virtualRow) => {
            const entry = entriesWithBalance[virtualRow.index];
            const isSelected = selectedRow === virtualRow.index;
            const isNegative = entry.balance < 0;
            const isOpening = virtualRow.index === 0;

            return (
              <div
                key={virtualRow.index}
                className="flex absolute top-0 left-0 w-full"
                style={{
                  height: `${virtualRow.size}px`,
                  transform: `translateY(${virtualRow.start}px)`,
                  backgroundColor: isSelected
                    ? "#e0ecf8"
                    : virtualRow.index % 2 === 0
                      ? "#fff"
                      : "#fafafa",
                  cursor: "pointer",
                  fontSize: 12,
                }}
                onClick={() => setSelectedRow(virtualRow.index)}
              >
                <div style={{ width: 60, padding: "2px 6px", textAlign: "center", borderRight: "1px solid #e0e0e0", borderBottom: "1px solid #e0e0e0", color: isOpening ? "#888" : "#333", flexShrink: 0 }}>
                  {entry.date}
                </div>
                <div style={{ width: 120, padding: "2px 6px", borderRight: "1px solid #e0e0e0", borderBottom: "1px solid #e0e0e0", color: isOpening ? "#888" : "#333", flexShrink: 0 }}>
                  <span className="truncate block">{entry.counterAccount}</span>
                </div>
                <div style={{ flex: 1, padding: "2px 6px", borderRight: "1px solid #e0e0e0", borderBottom: "1px solid #e0e0e0", color: isOpening ? "#888" : "#333", minWidth: 0 }}>
                  <span className="truncate block">{entry.summary}</span>
                </div>
                <div style={{ width: 110, padding: "2px 6px", textAlign: "right", borderRight: "1px solid #e0e0e0", borderBottom: "1px solid #e0e0e0", fontVariantNumeric: "tabular-nums", color: entry.debit ? "#005BAC" : "#ccc", flexShrink: 0 }}>
                  {fmt(entry.debit)}
                </div>
                <div style={{ width: 110, padding: "2px 6px", textAlign: "right", borderRight: "1px solid #e0e0e0", borderBottom: "1px solid #e0e0e0", fontVariantNumeric: "tabular-nums", color: entry.credit ? "#c0392b" : "#ccc", flexShrink: 0 }}>
                  {fmt(entry.credit)}
                </div>
                <div style={{ width: 120, padding: "2px 6px", textAlign: "right", borderBottom: "1px solid #e0e0e0", borderBottomWidth: "1px", fontVariantNumeric: "tabular-nums", color: isNegative ? "#e74c3c" : "#222", backgroundColor: isNegative ? "#fff5f5" : "transparent", flexShrink: 0 }}>
                  {isNegative && "△"}
                  {Math.abs(entry.balance).toLocaleString()}
                </div>
              </div>
            );
          })}
        </div>
      </div>

      {/* Footer */}
      <div
        className="flex items-center justify-between px-2"
        style={{
          height: 28,
          backgroundColor: "#e8e8e8",
          borderTop: "2px solid #005BAC",
          fontSize: 12,
        }}
      >
        <span style={{ color: "#555" }}>
          {selectedAccount}（{selectedSub}） 件数:{" "}
          {(entriesWithBalance.length - 1).toLocaleString()}件
        </span>
        <div className="flex items-center gap-6">
          <span>
            借方合計:{" "}
            <span style={{ color: "#005BAC", fontVariantNumeric: "tabular-nums" }}>
              ¥
              {entriesWithBalance
                .reduce((s, e) => s + (e.debit || 0), 0)
                .toLocaleString()}
            </span>
          </span>
          <span>
            貸方合計:{" "}
            <span style={{ color: "#c0392b", fontVariantNumeric: "tabular-nums" }}>
              ¥
              {entriesWithBalance
                .reduce((s, e) => s + (e.credit || 0), 0)
                .toLocaleString()}
            </span>
          </span>
          <span>
            残高:{" "}
            <span
              style={{
                fontVariantNumeric: "tabular-nums",
                color:
                  entriesWithBalance[entriesWithBalance.length - 1].balance < 0
                    ? "#e74c3c"
                    : "#27ae60",
              }}
            >
              ¥
              {Math.abs(
                entriesWithBalance[entriesWithBalance.length - 1].balance
              ).toLocaleString()}
            </span>
          </span>
        </div>
      </div>
    </div>
  );
}
